};

export type WheelStyle = {
  styleKey: string;
  brand: string;
  brandCode: string;
  model: string;
  imageUrl?: string;
  price?: number;
  finishes: Array<{
    finish: string;
    sku: string;
    imageUrl?: string;
    price?: number;
    diameter?: string;
    width?: string;
    offset?: string;
  }>;
  // All SKUs in this style for size filtering
  skus: Array<{
    sku: string;
