#!/usr/bin/env npx tsx

/**
 * Query Wheel-Size API for 10 random vehicles and output all fields
 */

import {
  getAllVehicleData,
  getModifications,
  getVehicleData,
  resolveMakeModel,
} from "../src/lib/wheelSizeApi";
import * as fs from "fs";

const TEST_VEHICLES = [
  { year: 2024, make: "Ford", model: "F-150" },
  { year: 2024, make: "Chevrolet", model: "Silverado 1500" },
  { year: 2024, make: "Ram", model: "1500" },
  { year: 2024, make: "Jeep", model: "Wrangler" },
  { year: 2024, make: "Toyota", model: "Tacoma" },
  { year: 2024, make: "Toyota", model: "Camry" },
  { year: 2024, make: "Honda", model: "Accord" },
  { year: 2024, make: "BMW", model: "3 Series" },
  { year: 2024, make: "Ford", model: "Mustang" },
  { year: 2024, make: "Chevrolet", model: "Corvette" },
];

async function main() {
  const results: any[] = [];

  console.log("Querying Wheel-Size API for 10 vehicles...\n");

  for (const vehicle of TEST_VEHICLES) {
    console.log(`\n─────────────────────────────────────────`);
    console.log(`Querying: ${vehicle.year} ${vehicle.make} ${vehicle.model}`);
    console.log(`─────────────────────────────────────────`);

    try {
      // Resolve make/model to slugs
      const resolved = await resolveMakeModel(vehicle.make, vehicle.model);
      if (!resolved) {
        console.log(`  ❌ Could not resolve make/model`);
        results.push({
          input: vehicle,
          error: "Could not resolve make/model",
        });
        continue;
      }

      console.log(`  Make slug: ${resolved.makeSlug}`);
      console.log(`  Model slug: ${resolved.modelSlug}`);

      // Get modifications (all engine variants)
      const modifications = await getModifications(
        resolved.makeSlug,
        resolved.modelSlug,
        vehicle.year
      );

      console.log(`  Found ${modifications.length} modifications`);

      // Filter to US market
      const usMods = modifications.filter(m => m.regions?.includes("usdm"));
      console.log(`  US market modifications: ${usMods.length}`);

      if (usMods.length === 0 && modifications.length > 0) {
        // Fall back to first modification if no US-specific
        console.log(`  (Using first modification as fallback)`);
      }

      const targetMod = usMods[0] || modifications[0];

      if (!targetMod) {
        console.log(`  ❌ No modifications found`);
        results.push({
          input: vehicle,
          resolved,
          error: "No modifications found",
        });
        continue;
      }

      console.log(`  Using modification: ${targetMod.slug}`);
      console.log(`  Modification name: ${targetMod.name}`);

      // Get full vehicle data
      const vehicleData = await getVehicleData(
        resolved.makeSlug,
        resolved.modelSlug,
        vehicle.year,
        targetMod.slug
      );

      if (!vehicleData) {
        console.log(`  ❌ No vehicle data returned`);
        results.push({
          input: vehicle,
          resolved,
          modification: targetMod,
          error: "No vehicle data returned",
        });
        continue;
      }

      console.log(`  ✅ Got vehicle data`);

      // Log some key fields
      console.log(`  Bolt pattern: ${vehicleData.technical?.bolt_pattern}`);
      console.log(`  Center bore: ${vehicleData.technical?.centre_bore}`);
      console.log(`  Wheel setups: ${vehicleData.wheels?.length || 0}`);

      results.push({
        input: vehicle,
        resolved,
        modification: targetMod,
        allModifications: modifications,
        usModifications: usMods,
        vehicleData,
      });

    } catch (err: any) {
      console.log(`  ❌ Error: ${err.message}`);
      results.push({
        input: vehicle,
        error: err.message,
      });
    }
  }

  // Write results to file
  const output = {
    generatedAt: new Date().toISOString(),
    totalVehicles: TEST_VEHICLES.length,
    successCount: results.filter(r => r.vehicleData).length,
    errorCount: results.filter(r => r.error).length,
    vehicles: results,
  };

  const outputPath = "wheelsize-sample-results.json";
  fs.writeFileSync(outputPath, JSON.stringify(output, null, 2));

  console.log(`\n═════════════════════════════════════════`);
  console.log(`Results written to: ${outputPath}`);
  console.log(`Success: ${output.successCount} / ${output.totalVehicles}`);
  console.log(`═════════════════════════════════════════\n`);
}

main().catch(err => {
  console.error("Fatal error:", err);
  process.exit(1);
});

#!/usr/bin/env npx tsx

/**
 * Query the fitment database to show all fields populated for sample vehicles
 */

import * as dotenv from "dotenv";
import pg from "pg";

// Load .env.local
dotenv.config({ path: ".env.local" });

const { Pool } = pg;

async function main() {
  const pool = new Pool({
    connectionString: process.env.POSTGRES_URL || process.env.DATABASE_URL,
    max: 3,
  });

  try {
    console.log("═══════════════════════════════════════════════════════════════");
    console.log("           FITMENT DATABASE - SAMPLE VEHICLE DATA");
    console.log("═══════════════════════════════════════════════════════════════\n");

    // Get 10 random vehicles with all their data
    const vehiclesResult = await pool.query(`
      SELECT 
        v.id,
        v.year,
        v.make,
        v.model,
        v.trim,
        v.search_trim,
        v.slug,
        v.market_regions,
        v.imported_from,
        v.imported_at,
        v.import_status,
        v.created_at,
        v.updated_at
      FROM vehicles v
      WHERE v.imported_at IS NOT NULL
      ORDER BY v.imported_at DESC
      LIMIT 10
    `);

    console.log(`Found ${vehiclesResult.rows.length} recently imported vehicles\n`);

    const results: any[] = [];

    for (const vehicle of vehiclesResult.rows) {
      console.log(`─────────────────────────────────────────────────────────────────`);
      console.log(`${vehicle.year} ${vehicle.make} ${vehicle.model} (ID: ${vehicle.id})`);
      console.log(`─────────────────────────────────────────────────────────────────`);

      // Get fitment data
      const fitmentResult = await pool.query(`
        SELECT 
          id,
          vehicle_id,
          bolt_pattern,
          center_bore,
          stud_holes,
          pcd,
          thread_size,
          fastener_type,
          torque_nm,
          imported_at,
          created_at,
          updated_at
        FROM vehicle_fitment
        WHERE vehicle_id = $1
      `, [vehicle.id]);

      const fitment = fitmentResult.rows[0] || null;

      // Get wheel specs
      const specsResult = await pool.query(`
        SELECT 
          id,
          vehicle_id,
          rim_diameter,
          rim_width,
          "offset",
          tire_size,
          axle,
          is_stock,
          imported_at,
          created_at,
          updated_at
        FROM vehicle_wheel_specs
        WHERE vehicle_id = $1
        ORDER BY rim_diameter, axle
      `, [vehicle.id]);

      const wheelSpecs = specsResult.rows;

      // Print summary
      console.log(`  Trim: ${vehicle.trim || '(none)'}`);
      console.log(`  Search Trim: ${vehicle.search_trim || '(none)'}`);
      console.log(`  Slug: ${vehicle.slug || '(none)'}`);
      console.log(`  Market Regions: ${vehicle.market_regions || '(none)'}`);
      console.log(`  Imported From: ${vehicle.imported_from || '(none)'}`);
      console.log(`  Imported At: ${vehicle.imported_at}`);

      if (fitment) {
        console.log(`\n  FITMENT DATA:`);
        console.log(`    Bolt Pattern: ${fitment.bolt_pattern}`);
        console.log(`    Center Bore: ${fitment.center_bore}mm`);
        console.log(`    Stud Holes: ${fitment.stud_holes}`);
        console.log(`    PCD: ${fitment.pcd}mm`);
        console.log(`    Thread Size: ${fitment.thread_size || '(not set)'}`);
        console.log(`    Fastener Type: ${fitment.fastener_type || '(not set)'}`);
        console.log(`    Torque: ${fitment.torque_nm ? fitment.torque_nm + ' Nm' : '(not set)'}`);
      } else {
        console.log(`\n  ⚠ NO FITMENT DATA`);
      }

      if (wheelSpecs.length > 0) {
        console.log(`\n  WHEEL SPECS (${wheelSpecs.length} configurations):`);
        for (const spec of wheelSpecs) {
          const offsetStr = spec.offset !== null ? `${spec.offset}mm offset` : 'no offset data';
          const axleStr = spec.axle === 'both' ? '' : ` (${spec.axle})`;
          const stockStr = spec.is_stock ? '✓ stock' : 'aftermarket';
          console.log(`    • ${spec.rim_diameter}" x ${spec.rim_width}" - ${offsetStr}${axleStr} [${stockStr}]`);
          if (spec.tire_size) {
            console.log(`      Tire: ${spec.tire_size}`);
          }
        }
      } else {
        console.log(`\n  ⚠ NO WHEEL SPECS`);
      }

      results.push({
        vehicle,
        fitment,
        wheelSpecs,
      });

      console.log('');
    }

    // Write full JSON results
    const output = {
      generatedAt: new Date().toISOString(),
      totalVehicles: results.length,
      vehicles: results,
    };

    const fs = await import("fs");
    fs.writeFileSync("fitment-db-sample.json", JSON.stringify(output, null, 2));

    console.log(`═══════════════════════════════════════════════════════════════`);
    console.log(`Full JSON data written to: fitment-db-sample.json`);
    console.log(`═══════════════════════════════════════════════════════════════\n`);

  } finally {
    await pool.end();
  }
}

main().catch(err => {
  console.error("Fatal error:", err);
  process.exit(1);
});

